      <MotorStatus />
    </el-tab-pane>
    <el-tab-pane label="Action" name="4">
      <ActionWheel />
    </el-tab-pane>
    <el-tab-pane label="Upgrade" name="5">
      <VersionUpgrade />
    </el-tab-pane>
  </el-tabs>
