<script>
import MotorStatus from './MotorStatus.vue'
import ActionWheel from './ActionWheel.vue'
import DebugPage from './DebugPage.vue'
import StatusPage from './StatusPage.vue'
import VersionUpgrade from './VersionUpgrade.vue'
import proto from '../assets/sdkapi_pb.js'

export default {
  name: 'MainPage',
  components: {
    MotorStatus,
    ActionWheel,
    DebugPage,
    StatusPage,
    VersionUpgrade,
  },
  props: {
    msg: String
  },
  data() {
    return {
      socket: '',
      wsUrl: 'ws://10.11.245.6:7123/status',
      activeIndex: '1',
      connected: false,
    };
  },
  created() {
    this.init();
  },
  methods: {
    handleSelect(key, keyPath) {
      console.log(key, keyPath);
    },
    onIndexChanged() {},
    init: function () {
      var that = this;
      this.wsUrl = "ws://" + window.location.hostname + ":7123/status";
      // this.wsUrl = "ws://" + "192.168.110.192" + ":7123/status";
      console.log("connect: " + this.wsUrl);
      this.$bus.$on("websocket-send-data", function(data) {
        that.send(data);
      });
      if (typeof(WebSocket) === "undefined") {
        alert("web socket unsupported!");
      } else {
        this.socket = new WebSocket(this.wsUrl);
        this.socket.onopen = this.open;
        this.socket.onerror = this.error;
        this.socket.onmessage = this.getMessage;
        this.socket.onclose = this.close;
      }
    },
    open: function () {
      console.log("socket connect success");
      this.getDataList();
    },
    error: function () {
      console.log("sokcet connect error");
      this.connected = false;
    },
    getMessage: function (msg) {
      this.blobToArrayBuffer(msg.data);
    },
    send: function (data) {
      var that = this;
      if (that.socket.readyState != 1) {
        console.error("websocket send error: ready state: " + that.socket.readyState);
        this.$nextTick(function() {
          that.$bus.$emit("websocket-error", { readyState:  that.socket.readyState });
        })
        return false;
      }
      that.socket.send(data.data);
      return true;
    },
    close: function () {
      console.log("socket close");
      this.connected = false;
    },
    blobToArrayBuffer(blob, callback) {
      var that = this;
      let reader = new FileReader();
      reader.onload = function() {
        var d = proto.Response.deserializeBinary(this.result);
        var j = proto.Response.toObject(null, d);
        if (j.command !== proto.Command.CMD_UPDATE_STATUS_DATA) {
          console.log("websocket-data-received", j, this.result);
        }
        that.$bus.$emit("websocket-data-received", { data: j, size: this.result.byteLength });
      }
      reader.readAsArrayBuffer(blob);
    },
    getDataList() {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_DATA_LIST);

      var d = request.serializeBinary();
      console.log("get data list start", request);
      this.send({ data: d });
    }
  }
}
</script>

