/* eslint-disable */
<template>
  <el-container style="height:100%">
    <el-main>
      <el-form id="uploadFile">

        <el-table ref="table" :data="versionDataList" style="width: 100%;height:100%" :key="isUpdate"
             :row-style="{ height: '40px', 'line-height': '40px' }">
          <el-table-column prop="desp" label="-" width="100">
            <template slot-scope="scope">
              {{scope.row.devdesp}}
            </template>
          </el-table-column>
          <el-table-column prop="progress" label="progress" width="500">
            <template slot-scope="scope">
              <div>
                <span style="display:inline;width:400px">
                  <el-progress :text-inside="true" :stroke-width="20" :percentage="scope.row.uploadParams.percent" :key="scope.row.uploadParams.percent"
                           :format="setProgressText(scope.row.uploadParams.index)">
                  </el-progress>
                </span>
              </div>
            </template>
          </el-table-column>
          <el-table-column prop="percent" label="percent" width="100">
             <template slot-scope="scope">
               <span :key="scope.row.uploadParams.percent">{{scope.row.uploadParams.percent}}&nbsp;%</span>
             </template>
          </el-table-column>
          <el-table-column prop="date" label="" width="">
            <template slot-scope="scope">
            <el-form-item
                :label="scope.row.uploadParams.label"
                :label-width="scope.row.uploadParams.labelWidth"
                :id="scope.row.uploadParams.key">
              <el-upload
                :data="scope.row"
                :ref="'upload'+scope.row.uploadParams.index"
                class="upload-demo"
                :before-upload="beforeUploadFile"
                action="null"
                :show-file-list="false"
                :http-request="handleUpload"
                :on-preview="handlePreview"
                :on-success="handleSuccess"
                :on-error="handleError"
                :before-remove="beforeRemove"
                :on-remove="handleRemove"
                :on-change="(file, fileList) => {handleChange(file, fileList, scope.row.uploadParams.index)}"
                :disabled="scope.row.uploadParams.disabled ? scope.row.uploadParams.disabled : false"
                :limit="scope.row.uploadParams.limit ? scope.row.uploadParams.limit : 1"
                :on-exceed="handleExceed"
                :file-list="scope.row.uploadParams.fileList"
                :auto-upload="false">
                <!-- el-button style="margin-left: 10px;" size="small" type="success" >上传</el-button-->
                <el-button slot="trigger" size="small" type="primary" :disabled="!scope.row.uploadParams.finished">选取文件</el-button>
                <el-button style="margin-left: 10px;" size="small" type="success" @click="submitUpload(scope.row.uploadParams.index)" :disabled="!scope.row.uploadParams.finished">上传</el-button>
                <el-button style="margin-left: 10px;" size="small" type="success" @click="submitUpgrade(scope.row.uploadParams.index)" :disabled="!scope.row.uploadParams.finished">升级</el-button>
                <el-button style="margin-left: 10px;" size="small" type="success" @click="clearUpload(scope.row.uploadParams.index)" :disabled="!scope.row.uploadParams.finished">删除</el-button>
              </el-upload>
            </el-form-item>
            </template>
          </el-table-column>
        </el-table>
      </el-form>
    </el-main>
    <!--el-footer height="0px" >
      <div id="chart-motor-status" style="height:100%;width:100%;"></div>
    </el-footer-->
  </el-container>
</template>

<script>
// import proto from "../assets/sdkapi_pb.js"
import VersionUpgrade from "../assets/version_upgrade.js"
import proto from "../assets/sdkapi_pb.js"
export default {
  name: "uploadFile",
  props: {
  },
  data() {
    this.server = window.location.hostname;
    // this.server = "192.168.110.192";
    return {
      fileIdList: [],//存放附件id数组
      actionUrl: process.env.VUE_APP_BASE_API + "xxxx/xxxx",//文件上传地址
      removeUrl: 'xxxx/xxx',// 删除文件地址
      uploadParams: { type: ".tar.gz", fileList: [], labelWidth: 20, label: "123" },
      paramsData: {},
      versionDataList: [],
      isUpdate: 0,
    }
  },
  created() {},
  mounted() {
    var that = this;
    this.$bus.$on("websocket-data-received", function(d) {
      var data = d.data;
      if (data.command == proto.Command.CMD_UPDATE_STATUS_DATA) {
        that.updateStatusData(data, d.size);
      }
    });
  },
  methods: {
    updateStatusData(data, size) {
      if (data.statusData && data.statusData.versionDataList && this.versionDataList.length === 0) {
        this.versionDataList = data.statusData.versionDataList;
        this.versionDataList.forEach((v, index) => {
          v.uploadParams = {
            index: index,
            key: "upload" + index,
            // label: v.devdesp,
            label: "",
            labelWidth: "",
            limit: 0,
            fileList: [],
            filename: '',
            file: null,
            percent: 0,
            finished: true,
          };
        });
      }
    },
    handleChange(file, fileList, index) {
      this.versionDataList[index].uploadParams.filename = file.name;
      this.versionDataList[index].uploadParams.file = file;
      this.isUpdate = !this.isUpdate;
      console.log("handle change", file, fileList);
    },
    setProgressText(index) {
      return () => {
        if (this.versionDataList[index].uploadParams) {
          return this.versionDataList[index].uploadParams.filename;
        }
        return index + "";
      }
    },
    submitUpload(index) {
      // this.$refs["upload" + index].submit();
      var obj = {
        index: index,
        devid: this.versionDataList[index].devid,
        devname: this.versionDataList[index].devname,
        package_name: this.versionDataList[index].uploadParams.filename,
        onEventUploadPercent: this.onEventUploadPercent,
        onEventUploadFinished: this.onEventUploadFinished,
        onEventAlertMessage: this.onEventAlertMessage,
        onEventErrorMessage: this.onEventErrorMessage,
      };
      this.versionDataList[index].uploadParams.finished = false;
      this.isUpdate = !this.isUpdate;
      console.log("submit upload: ", index, obj);
      this.handleUpload(this.versionDataList[index].uploadParams.file, obj);
    },
    submitUpgrade(index) {
      var obj = {
        index: index,
        devid: this.versionDataList[index].devid,
        devname: this.versionDataList[index].devname,
        package_name: this.versionDataList[index].uploadParams.filename,
        onEventUploadPercent: this.onEventUploadPercent,
        onEventUploadFinished: this.onEventUploadFinished,
        onEventAlertMessage: this.onEventAlertMessage,
        onEventErrorMessage: this.onEventErrorMessage,
      };
      this.versionDataList[index].uploadParams.finished = false;
      this.isUpdate = !this.isUpdate;
      console.log("submit upload: ", index, obj);
      this.handleUpgrade(obj);
    },
    onEventUploadPercent(obj, data) {
      if (this.versionDataList[obj.index].uploadParams.percent !== data.percent) {
        var that = this;
        this.$nextTick(function() {
          var change = that.versionDataList[obj.index];
          change.uploadParams.percent = data.percent;
          that.isUpdate = !this.isUpdate;
        });
      }
    },
    onEventUploadFinished(obj, data) {
      var that = this;
      this.$nextTick(function() {
        var change = that.versionDataList[obj.index];
        change.uploadParams.finished = true;
        change.uploadParams.percent = 100;
        // that.isUpdate = !that.isUpdate;
        this.$refs.table.doLayout();
      });
    },
    onEventAlertMessage(obj, data) {
      console.log("==== alert message", data);
      var that = this;
      this.$nextTick(function() {
        const h = this.$createElement;
        this.$notify({
          title: data.alert_type,
          message: h('i', { style: 'color: teal'}, data.versionUpdateResponse.alertMessage)
        });
        if (data.versionUpdateResponse.upgradeFinished === true) {
          var change = that.versionDataList[obj.index];
          change.uploadParams.finished = true;
          that.isUpdate = !that.isUpdate;
        }
      });
    },
    onEventErrorMessage(obj, data) {
      console.log("==== error message", data);
      var that = this;
      this.$nextTick(function() {
        var errorCode = data.errorCode;
        var errorMessage = data.errorMessage;
        if (data.versionUpdateResponse && data.versionUpdateResponse.errorCode) {
          errorCode = data.versionUpdateResponse.errorCode;
        }
        if (data.versionUpdateResponse && data.versionUpdateResponse.errorMessage) {
          errorMessage = data.versionUpdateResponse.errorMessage;
        }
        const h = this.$createElement;
        this.$notify({
          title: "Error " + "[" + errorCode + "]",
          message: h('i', { style: 'color: teal'}, errorMessage),
          customClass: 'resume-info-notification-style'
        });
        if (data.versionUpdateResponse && data.versionUpdateResponse.upgradeFinished === true) {
          var change = that.versionDataList[obj.index];
          change.uploadParams.finished = true;
          that.isUpdate = !that.isUpdate;
        }
      });
    },
    clearUpload(index) {
      this.$refs["upload" + index].clearFiles();
    },
    // 文件上传成功时的钩子
    handleSuccess(res, file, fileList) {
      this.$message.success("文件上传成功");
      // let filename = fileList.map(item => {
      //   return item.name;
      // });
      this.fileIdList.push(res.data.fid);
      this.$emit("getFileIdReturn", this.fileIdList);//返回文件id数组
    },
    // 文件上传失败时的钩子
    handleError() {
      this.$message.error("文件上传失败");
    },
    handleExceed(files, fileList) {
      //上传超过限制个数
      this.$message.warning(`当前限制选择 ${this.uploadParams.limit} 个文件，本次选择了 ${ files.length } 个文件，
        共选择了 ${files.length + fileList.length} 个文件`
        );
      },
      beforeRemove(file, fileList) {
        if(file.url==undefined){
          return;
        }
        // 移除前钩子
        return this.$confirm(`确定移除 ${file.name}？`)
      },
 
      // 上传文件之前的钩子, 参数为上传的文件,若返回 false 或者返回 Promise 且被 reject，则停止上传
      beforeUploadFile(file) {
        console.log('before upload')
        // console.log(file)
        const extension = file.name.substr(file.name.lastIndexOf('.') + 1);
        console.log('extension', extension)
        const size = file.size / 1024 / 1024;
        let temp = this.uploadParams.type.split(",");
        let typeArr = [];
        temp.forEach(element => {
          typeArr.push(element.substr(element.lastIndexOf('.') + 1));
        });
        if (!(typeArr.includes(extension)) ) {
          this.$message.warning(`只能上传后缀是${this.uploadParams.type}的文件`)
          return false
        }
        if (size > this.uploadParams.fileSize) {
          this.$message.warning(`文件大小不得超过${this.uploadParams.fileSize}M`)
          return false
        }
        return extension && size
      },
      handleRemove(file, fileList) {
        // 移除附件时钩子
        console.log(file);
        let id; 
        if(file.url) {
          id = file.url.split("id=")[1];
        }else if(file.response) {
          id = file.response.data.fid;
        }else {
          this.uploadParams.fileList = fileList;
          return
        }
        window.request({
          url: this.removeUrl,
          data: {
            ids: id
          },
          success: (res) => {
            if(res.code === 200) {
              this.$message.success("删除成功！");
              this.uploadParams.fileList = fileList;
              this.fileIdList.forEach((element, index) =>{
                if(element == id) {
                  this.fileIdList.splice(index, 1);
                }
              });
              this.handLoadingShow(false)
              this.$emit("getFileIdReturn", this.fileIdList);//返回文件id数组
            }
          }
        })
      },
      handleUpload(file, ddd) {
        console.log("---- handle upload: ", file, ddd);
        var uploadjs = new VersionUpgrade(file.raw);
        var url = "ws://" + this.server + ":7123/version/upgrade";
        uploadjs.setSocketUrl(url);
        uploadjs.startUpload(file.raw, ddd);
      },
      handleUpgrade(obj) {
        console.log("---- handle upgrade: ", obj);
        var uploadjs = new VersionUpgrade(null);
        var url = "ws://" + this.server + ":7123/version/upgrade";
        uploadjs.setSocketUrl(url);
        uploadjs.startUpgrade(obj);
      },
      handlePreview(file) {
        //点击文件列表中已上传的文件时的钩子
        console.log(file);
        let fileurl;
        if(file.url) {
          // fileurl = Config.downUrl + file.url;
        }else {
          // fileurl = Config.downUrl + process.env.VUE_APP_BASE_API + "xxx/下载地址" + file.response.data.fid;
        }
        window.location.href = fileurl;
      },
      // 上传控件的回显====回显加载时使用
      loadFileList (urlAndFid) {//参数url加文件
        let templateList = null;
        const downloadUrl = process.env.VUE_APP_BASE_API + "xxx/xxx";
        this.uploadParams.fileList = [];
        this.fileIdList = [];
        window.request({
          url: urlAndFid,
          success: ({ data }) => {
            templateList = data;
            templateList.forEach((element, index) => {
              const obj = {};
              obj.name = templateList[index].name;
              obj.url = downloadUrl + templateList[index].id;
              obj.id = templateList[index].id;
            this.uploadParams.fileList.push(obj);
            this.fileIdList.push(obj.id);
          });
          this.$emit("getFileIdReturn", this.fileIdList);//返回文件id数组
          }
        });
      },
      loadFileList2 (fileUrl, fileParam) {//url: fileUrl,参数fileParam
        let templateList = null;
        const downloadUrl = process.env.VUE_APP_BASE_API + "xxx/xxx";
        this.uploadParams.fileList = [];
        this.fileIdList = [];
        window.request({
          url: fileUrl,
          data: fileParam,
          success: ({ data }) => {
            templateList = data;
            templateList.forEach((element, index) => {
              const obj = {};
              obj.name = templateList[index].name;
              obj.url = downloadUrl + templateList[index].id;
              obj.id = templateList[index].id;
              this.uploadParams.fileList.push(obj);
              this.fileIdList.push(obj.id);
            });
            this.$emit("getFileIdReturn", this.fileIdList);//返回文件id数组
          }
        });
      },
  }
}
</script>

